const input = ($json.body && typeof $json.body === 'object' && !Array.isArray($json.body))
  ? $json.body
  : $json;

const now = new Date();
const nowIso = now.toISOString();
const defaultForbiddenActions = [
  'architecture_change',
  'code_write',
  'branch_create',
  'pull_request_create',
  'merge',
  'production_deploy',
  'auth_change',
  'rls_change',
  'sql_execute',
  'migration_create_or_apply',
  'secret_access_or_change',
  'production_private_data_access',
  'docs_index_edit',
  'knowledge_debt_close',
  'beta_ready_claim',
  'release_ready_claim'
];

function cleanString(value, maxLength = 4000) {
  if (typeof value !== 'string') return '';
  return value.trim().replace(/\s+/g, ' ').slice(0, maxLength);
}

function cleanStringArray(value, maxItems = 30, maxLength = 120) {
  if (!Array.isArray(value)) return [];
  return [...new Set(value
    .filter((item) => typeof item === 'string')
    .map((item) => cleanString(item, maxLength))
    .filter(Boolean))]
    .slice(0, maxItems);
}

function stableValue(value) {
  if (Array.isArray(value)) return value.map(stableValue);
  if (value && typeof value === 'object') {
    return Object.keys(value).sort().reduce((out, key) => {
      out[key] = stableValue(value[key]);
      return out;
    }, {});
  }
  return value;
}

function stableStringify(value) {
  return JSON.stringify(stableValue(value));
}

function fnv1a(value) {
  let hash = 0x811c9dc5;
  for (let index = 0; index < value.length; index += 1) {
    hash ^= value.charCodeAt(index);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(16).padStart(8, '0');
}

function roundMoney(value) {
  return Math.round((value + Number.EPSILON) * 100) / 100;
}

const errors = [];
const title = cleanString(input.title, 200);
const objective = cleanString(input.objective, 2000);
const businessReason = cleanString(input.business_reason, 1000);
const expectedDeliverable = cleanString(input.expected_deliverable, 1000);
const requestedBy = cleanString(input.requested_by || 'owner', 100);
const source = ['owner', 'github_issue', 'manual', 'scheduled'].includes(input.source)
  ? input.source
  : 'owner';
const priority = ['low', 'normal', 'high', 'critical'].includes(input.priority)
  ? input.priority
  : 'normal';

if (!title) errors.push({ field: 'title', code: 'required' });
if (!objective) errors.push({ field: 'objective', code: 'required' });
if (!expectedDeliverable) errors.push({ field: 'expected_deliverable', code: 'required' });

const parsedBudget = Number(input.maximum_budget_usd ?? 0.75);
const maximumBudgetUsd = Number.isFinite(parsedBudget) ? roundMoney(parsedBudget) : NaN;
if (!Number.isFinite(maximumBudgetUsd) || maximumBudgetUsd < 0.01 || maximumBudgetUsd > 5) {
  errors.push({ field: 'maximum_budget_usd', code: 'must_be_between_0.01_and_5' });
}

let deadline = null;
if (input.deadline !== undefined && input.deadline !== null && input.deadline !== '') {
  const parsedDeadline = new Date(input.deadline);
  if (Number.isNaN(parsedDeadline.getTime())) {
    errors.push({ field: 'deadline', code: 'invalid_date_time' });
  } else {
    deadline = parsedDeadline.toISOString();
  }
}

let relatedGithubIssue = null;
if (input.related_github_issue !== undefined && input.related_github_issue !== null && input.related_github_issue !== '') {
  const issueText = String(input.related_github_issue).trim().replace(/^#/, '');
  if (!/^\d+$/.test(issueText) || Number(issueText) < 1) {
    errors.push({ field: 'related_github_issue', code: 'invalid_issue_number' });
  } else {
    relatedGithubIssue = Number(issueText);
  }
}

const suppliedMissionId = cleanString(input.mission_id, 80);
if (suppliedMissionId && !/^[A-Za-z0-9][A-Za-z0-9._-]{5,79}$/.test(suppliedMissionId)) {
  errors.push({ field: 'mission_id', code: 'invalid_format' });
}

const allowedWriteScope = cleanStringArray(input.allowed_write_scope, 30, 160);
const forbiddenActions = cleanStringArray(input.forbidden_actions, 50, 160);
const effectiveForbiddenActions = [...new Set([...defaultForbiddenActions, ...forbiddenActions])];
const metadata = input.metadata && typeof input.metadata === 'object' && !Array.isArray(input.metadata)
  ? input.metadata
  : {};

if (errors.length > 0) {
  return [{
    json: {
      accepted: false,
      duplicate: false,
      status: 'invalid',
      http_status: 400,
      received_at: nowIso,
      error: {
        code: 'VALIDATION_FAILED',
        message: 'Daily Mission input failed validation.',
        fields: errors
      },
      routing: {
        mode: 'report-only',
        ready: false,
        next_workflow: null
      }
    }
  }];
}

const canonicalMission = {
  title,
  objective,
  business_reason: businessReason || null,
  expected_deliverable: expectedDeliverable,
  priority,
  maximum_budget_usd: maximumBudgetUsd,
  related_github_issue: relatedGithubIssue,
  allowed_write_scope: allowedWriteScope,
  forbidden_actions: effectiveForbiddenActions,
  deadline,
  requested_by: requestedBy,
  source,
  metadata
};

const missionHash = fnv1a(stableStringify(canonicalMission));
const dateStamp = nowIso.slice(0, 10).replace(/-/g, '');
const missionId = suppliedMissionId || ('MISSION-' + dateStamp + '-' + missionHash.toUpperCase());
const mission = {
  mission_id: missionId,
  mission_hash: missionHash,
  received_at: nowIso,
  ...canonicalMission
};

const workflowData = $getWorkflowStaticData('global');
if (!workflowData.staff00 || typeof workflowData.staff00 !== 'object') {
  workflowData.staff00 = { records: {} };
}
if (!workflowData.staff00.records || typeof workflowData.staff00.records !== 'object') {
  workflowData.staff00.records = {};
}

const records = workflowData.staff00.records;
const retentionCutoff = now.getTime() - (7 * 24 * 60 * 60 * 1000);
for (const [hash, record] of Object.entries(records)) {
  const timestamp = Date.parse(record.received_at || '');
  if (!Number.isFinite(timestamp) || timestamp < retentionCutoff) {
    delete records[hash];
  }
}

const existing = records[missionHash];
if (existing) {
  existing.last_seen_at = nowIso;
  existing.duplicate_count = Number(existing.duplicate_count || 0) + 1;
  return [{
    json: {
      accepted: true,
      duplicate: true,
      status: 'duplicate',
      http_status: 200,
      received_at: nowIso,
      mission: existing.mission,
      duplicate_guard: {
        storage: 'workflow_static_data',
        original_received_at: existing.received_at,
        duplicate_count: existing.duplicate_count
      },
      routing: {
        mode: 'report-only',
        ready: false,
        next_workflow: null,
        reason: 'cached_mission_hash'
      }
    }
  }];
}

const record = {
  mission_id: missionId,
  mission_hash: missionHash,
  received_at: nowIso,
  last_seen_at: nowIso,
  duplicate_count: 0,
  mission
};
records[missionHash] = record;

const sortedRecords = Object.entries(records)
  .sort((a, b) => Date.parse(b[1].received_at) - Date.parse(a[1].received_at));
for (const [hash] of sortedRecords.slice(100)) {
  delete records[hash];
}

const reservedUsd = roundMoney(maximumBudgetUsd * 0.25);
const dispatchBudgetUsd = roundMoney(maximumBudgetUsd - reservedUsd);

return [{
  json: {
    accepted: true,
    duplicate: false,
    status: 'received',
    http_status: 201,
    mission,
    budget_policy: {
      maximum_budget_usd: maximumBudgetUsd,
      reserve_percent: 25,
      reserved_usd: reservedUsd,
      dispatch_budget_usd: dispatchBudgetUsd,
      optional_roles_stop_at_percent: 75,
      malformed_output_repairs_max: 1,
      provider_fallbacks_max: 1,
      critic_cycles_max: 1
    },
    guardrails: {
      report_only: true,
      allowed_write_scope: allowedWriteScope,
      forbidden_actions: effectiveForbiddenActions,
      private_or_secret_data_allowed: false
    },
    duplicate_guard: {
      storage: 'workflow_static_data',
      retention_days: 7,
      maximum_records: 100
    },
    routing: {
      mode: 'report-only',
      ready: true,
      next_workflow: 'STAFF-01 Project Coordinator'
    }
  }
}];
